styles:
    *,
    *::before,
    *::after {
      box-sizing: border-box;
      margin: 0;
      padding: 0;
    }

    html,
    body {
      height: 100%;
    }

    :root {
      --blue: #448AFF;
      --blue-dark: #3a7aee;
      --blue-light: #8AB6FF;
      --blue-pale: #DBE8FF;
      --cream: #FFFEF4;
      --text: #1a1a1a;
      --muted: #8e8e8e;
      --blue-ring: rgba(68, 138, 255, 0.15);
      --surface: rgba(255, 254, 244, 0.92);
      --radius-lg: 20px;
      --radius-md: 12px;
      --radius-sm: 8px;
    }

    body {
      font-family: 'Montserrat', sans-serif;
      -webkit-font-smoothing: antialiased;
      -moz-osx-font-smoothing: grayscale;
      min-height: 100vh;
      overflow: hidden;
    }

    .page-backdrop {
      min-height: 100vh;
      background: linear-gradient(
        180deg,
        #DBE8FF 0%,
        #8AB6FF 27%,
        #448AFF 50%,
        #8AB6FF 77%,
        #DBE8FF 100%
      );
      filter: blur(10px);
      transform: scale(1.02);
      pointer-events: none;
      user-select: none;
    }

    .shell {
      display: grid;
      grid-template-columns: minmax(0, 1fr) minmax(calc(550px + 112px), 1fr);
      min-height: 100vh;
      width: 100%;
    }

    .hero {
      display: flex;
      flex-direction: column;
      align-items: center;
      justify-content: center;
      text-align: center;
      color: #fff;
      padding: 48px 32px;
    }

    .logo-wrap {
      display: flex;
      justify-content: center;
      line-height: 0;
      margin-bottom: -30px;
    }

    .logo {
      width: 260px;
      height: auto;
      display: block;
      mix-blend-mode: screen;
      filter: drop-shadow(0 6px 12px rgba(0, 40, 80, 0.12));
    }

    .greeting {
      font-size: 28px;
      font-weight: 700;
      line-height: 1.2;
      margin-bottom: 12px;
      color: #fff;
    }

    .form-panel {
      background: var(--cream);
      box-shadow: -12px 0 40px rgba(0, 40, 90, 0.1);
      padding: 36px 56px 40px;
      margin-left: -24px;
      min-height: 100vh;
    }

    .form-inner {
      width: 550px;
      max-width: 100%;
    }

    .page-title {
      font-size: 30px;
      font-weight: 700;
      color: var(--blue);
      margin-bottom: 26px;
    }

    .section-title {
      font-size: 19px;
      font-weight: 700;
      color: var(--text);
      margin-bottom: 6px;
    }

    .section-copy {
      font-size: 13px;
      font-weight: 500;
      color: var(--text);
      margin-bottom: 24px;
    }

    .fake-input {
      height: 44px;
      border-radius: var(--radius-sm);
      background: rgba(68, 138, 255, 0.06);
      box-shadow: inset 0 1px 2px rgba(0, 40, 90, 0.03);
    }

    .modal-overlay {
      position: fixed;
      inset: 0;
      z-index: 100;
      display: flex;
      align-items: center;
      justify-content: center;
      padding: 24px;
      background: rgba(219, 232, 255, 0.35);
      backdrop-filter: blur(2px);
      -webkit-backdrop-filter: blur(2px);
    }

    .page {
      position: relative;
      width: 100%;
      max-width: 560px;
      display: flex;
      flex-direction: column;
      max-height: calc(100vh - 48px);
    }

    .card {
      display: flex;
      flex-direction: column;
      background: var(--surface);
      backdrop-filter: blur(16px);
      -webkit-backdrop-filter: blur(16px);
      border-radius: var(--radius-lg);
      box-shadow:
        0 4px 6px rgba(0, 40, 90, 0.04),
        0 24px 48px rgba(0, 40, 90, 0.14);
      border: 1px solid rgba(255, 255, 255, 0.6);
      overflow: hidden;
      max-height: calc(100vh - 48px);
    }

    .card-header {
      padding: 28px 28px 0;
      flex-shrink: 0;
    }

    .header-top {
      display: flex;
      align-items: flex-start;
      justify-content: space-between;
      gap: 16px;
      margin-bottom: 20px;
    }

    .step-badge {
      display: inline-flex;
      align-items: center;
      gap: 6px;
      padding: 5px 12px;
      border-radius: 999px;
      background: rgba(68, 138, 255, 0.1);
      font-size: 10px;
      font-weight: 700;
      letter-spacing: 0.06em;
      text-transform: uppercase;
      color: var(--blue);
    }

    .step-badge svg {
      width: 12px;
      height: 12px;
      flex-shrink: 0;
    }

    .back-btn {
      display: inline-flex;
      align-items: center;
      justify-content: center;
      width: 34px;
      height: 34px;
      border: none;
      border-radius: 50%;
      background: rgba(68, 138, 255, 0.08);
      color: var(--blue);
      text-decoration: none;
      cursor: pointer;
      flex-shrink: 0;
      transition: background 0.15s ease, transform 0.1s ease;
    }

    .back-btn svg {
      width: 16px;
      height: 16px;
    }

    .back-btn:hover {
      background: rgba(68, 138, 255, 0.16);
    }

    .back-btn:active {
      transform: scale(0.96);
    }

    .title-block {
      display: flex;
      align-items: flex-start;
      gap: 14px;
    }

    .title-icon {
      flex-shrink: 0;
      width: 44px;
      height: 44px;
      display: flex;
      align-items: center;
      justify-content: center;
      border-radius: var(--radius-md);
      background: linear-gradient(135deg, var(--blue) 0%, var(--blue-light) 100%);
      color: #fff;
      box-shadow: 0 6px 16px rgba(68, 138, 255, 0.3);
    }

    .title-icon svg {
      width: 22px;
      height: 22px;
    }

    .title-text h1 {
      font-size: 22px;
      font-weight: 700;
      color: var(--blue);
      line-height: 1.25;
      margin-bottom: 4px;
    }

    .title-text p {
      font-size: 12px;
      font-weight: 500;
      color: var(--muted);
      line-height: 1.45;
    }

    .card-body {
      flex: 1;
      overflow-y: auto;
      padding: 20px 28px 8px;
      scrollbar-width: thin;
      scrollbar-color: var(--blue-light) transparent;
    }

    .card-body::-webkit-scrollbar {
      width: 5px;
    }

    .card-body::-webkit-scrollbar-thumb {
      background: var(--blue-light);
      border-radius: 999px;
    }

    .policy-block {
      padding: 18px 20px;
      border-radius: var(--radius-md);
      background: rgba(68, 138, 255, 0.05);
      border: 1px solid rgba(68, 138, 255, 0.1);
      margin-bottom: 14px;
    }

    .policy-block:last-child {
      margin-bottom: 0;
    }

    .policy-block h2 {
      display: flex;
      align-items: center;
      gap: 8px;
      font-size: 13px;
      font-weight: 700;
      color: var(--blue);
      margin-bottom: 10px;
      line-height: 1.3;
    }

    .policy-block h2 span {
      display: inline-flex;
      align-items: center;
      justify-content: center;
      width: 22px;
      height: 22px;
      border-radius: 6px;
      background: rgba(68, 138, 255, 0.12);
      font-size: 11px;
      font-weight: 800;
      color: var(--blue);
      flex-shrink: 0;
    }

    .policy-block p {
      font-size: 12px;
      font-weight: 400;
      color: var(--text);
      line-height: 1.65;
    }

    .policy-list {
      list-style: none;
      margin-top: 10px;
      display: flex;
      flex-direction: column;
      gap: 6px;
    }

    .policy-list li {
      position: relative;
      padding-left: 16px;
      font-size: 11px;
      font-weight: 500;
      color: var(--muted);
      line-height: 1.45;
    }

    .policy-list li::before {
      content: '';
      position: absolute;
      left: 0;
      top: 6px;
      width: 6px;
      height: 6px;
      border-radius: 50%;
      background: var(--blue-light);
    }

    .card-footer {
      flex-shrink: 0;
      padding: 16px 28px 24px;
      border-top: 1px solid rgba(68, 138, 255, 0.1);
      background: rgba(255, 254, 244, 0.6);
    }

    .consent-card {
      display: flex;
      align-items: flex-start;
      gap: 12px;
      padding: 14px 16px;
      border-radius: var(--radius-md);
      background: #fff;
      border: 1.5px solid transparent;
      cursor: pointer;
      transition: border-color 0.15s ease, box-shadow 0.15s ease;
      margin-bottom: 16px;
    }

    .consent-card:hover {
      border-color: rgba(68, 138, 255, 0.2);
    }

    .consent-card.is-checked {
      border-color: var(--blue);
      box-shadow: 0 0 0 3px var(--blue-ring);
    }

    .consent-card input {
      position: absolute;
      opacity: 0;
      width: 0;
      height: 0;
    }

    .consent-toggle {
      flex-shrink: 0;
      width: 20px;
      height: 20px;
      margin-top: 1px;
      border-radius: 6px;
      border: 2px solid rgba(68, 138, 255, 0.35);
      background: #fff;
      display: flex;
      align-items: center;
      justify-content: center;
      transition: background 0.15s ease, border-color 0.15s ease;
    }

    .consent-toggle svg {
      width: 12px;
      height: 12px;
      opacity: 0;
      color: #fff;
      transition: opacity 0.15s ease;
    }

    .consent-card input:checked ~ .consent-toggle {
      background: var(--blue);
      border-color: var(--blue);
    }

    .consent-card input:checked ~ .consent-toggle svg {
      opacity: 1;
    }

    .consent-card input:focus-visible ~ .consent-toggle {
      box-shadow: 0 0 0 3px var(--blue-ring);
    }

    .consent-text {
      font-size: 12px;
      font-weight: 500;
      color: var(--text);
      line-height: 1.55;
    }

    .footer-actions {
      display: flex;
      align-items: center;
      gap: 12px;
    }

    .btn-create {
      flex: 1;
      height: 44px;
      padding: 0 24px;
      border: none;
      border-radius: var(--radius-sm);
      background: var(--blue);
      color: #fff;
      font-family: 'Montserrat', sans-serif;
      font-size: 12px;
      font-weight: 700;
      letter-spacing: 0.04em;
      text-transform: uppercase;
      cursor: pointer;
      transition: background 0.15s ease, opacity 0.15s ease, transform 0.1s ease;
      box-shadow: 0 6px 18px rgba(68, 138, 255, 0.28);
    }

    .btn-create:hover:not(:disabled) {
      background: var(--blue-dark);
    }

    .btn-create:active:not(:disabled) {
      transform: scale(0.99);
    }

    .btn-create:disabled {
      opacity: 0.4;
      cursor: not-allowed;
      box-shadow: none;
    }

    .progress-dots {
      display: flex;
      justify-content: center;
      gap: 6px;
      margin-top: 18px;
    }

    .progress-dots span {
      width: 6px;
      height: 6px;
      border-radius: 50%;
      background: rgba(68, 138, 255, 0.25);
    }

    .progress-dots span.is-active {
      width: 20px;
      border-radius: 999px;
      background: var(--blue);
    }

    @media (max-width: 1024px) {
      .shell {
        grid-template-columns: 1fr;
      }

      .form-panel {
        margin-left: 0;
        min-height: 60vh;
      }
    }

    @media (max-width: 480px) {
      .modal-overlay {
        padding: 16px 14px;
        align-items: flex-start;
      }

      .page {
        max-height: none;
      }

      .card {
        max-height: none;
      }

      .card-header {
        padding: 22px 20px 0;
      }

      .card-body {
        padding: 16px 20px 8px;
        overflow-y: visible;
      }

      .card-footer {
        padding: 14px 20px 20px;
      }

      .title-text h1 {
        font-size: 19px;
      }

      .footer-actions {
        flex-direction: column;
      }

      .btn-create {
        width: 100%;
      }
    }

scripts.value:
var consent = document.getElementById('consent');
    var submitBtn = document.getElementById('submitBtn');
    var consentCard = document.getElementById('consentCard');

    function syncConsent() {
      submitBtn.disabled = !consent.checked;
      consentCard.classList.toggle('is-checked', consent.checked);
    }

    consent.addEventListener('change', syncConsent);
    syncConsent();
